							(
								rslt_idx_std_iem_id
								, rslt_idx_id
								, std_iem_nm
								, iem_unit_cd
								, creator_id
								, created_dt
								, updater_id
								, updated_dt
							)
					values	(
								#{rsltIdxStdIemId}
								, #{rsltIdxId}
								, #{stdIemNm}
								, #{iemUnitCd}
								, #{creatorId}
								, #{createdDt}
								, #{updaterId}
								, #{updatedDt}
							)

mapper.update:
/** UsptStdrRsltIdxStdIemDao.update */
update uspt_stdr_rslt_idx_std_iem
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, std_iem_nm	= #{stdIemNm}
	, iem_unit_cd	= #{iemUnitCd}
where
	rslt_idx_std_iem_id = #{rsltIdxStdIemId}
	and rslt_idx_id = #{rsltIdxId}

